import Link from "next/link"
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card"
import { Button } from "@/components/ui/button"
import { Badge } from "@/components/ui/badge"
import type { Career } from "@/lib/sample-data"
import { ArrowRight, TrendingUp } from "lucide-react"
import Image from "next/image"

interface CareerCardProps {
  career: Career
}

export function CareerCard({ career }: CareerCardProps) {
  const demandColor = {
    High: "bg-secondary text-secondary-foreground",
    Medium: "bg-accent text-accent-foreground",
    Low: "bg-muted text-muted-foreground",
  }

  return (
    <Card className="hover:shadow-lg transition-shadow overflow-hidden h-full flex flex-col">
      <div className="relative h-48 w-full bg-muted">
        <Image src={career.imageUrl || "/placeholder.svg"} alt={career.title} fill className="object-cover" />
      </div>

      <CardHeader>
        <div className="flex items-start justify-between gap-2 mb-2">
          <CardTitle className="text-xl">{career.title}</CardTitle>
          <Badge className={demandColor[career.demand]} variant="secondary">
            <TrendingUp className="w-3 h-3 mr-1" />
            {career.demand}
          </Badge>
        </div>
        <CardDescription className="line-clamp-2">{career.description}</CardDescription>
      </CardHeader>

      <CardContent className="flex-1 flex flex-col justify-between">
        <div className="space-y-4 mb-4">
          <div>
            <p className="text-sm font-medium mb-2">Required Skills:</p>
            <div className="flex flex-wrap gap-2">
              {career.skills.slice(0, 4).map((skill) => (
                <Badge key={skill} variant="outline" className="text-xs">
                  {skill}
                </Badge>
              ))}
              {career.skills.length > 4 && (
                <Badge variant="outline" className="text-xs">
                  +{career.skills.length - 4} more
                </Badge>
              )}
            </div>
          </div>

          <div>
            <p className="text-sm font-medium">Salary Range:</p>
            <p className="text-sm text-muted-foreground">{career.salary}</p>
          </div>
        </div>

        <Link href={`/careers/${career.id}`}>
          <Button className="w-full gap-2">
            View Details
            <ArrowRight className="w-4 h-4" />
          </Button>
        </Link>
      </CardContent>
    </Card>
  )
}
